// ── availability-engine / next-free ──────────────────────────────────────────
// Input: POST body with customer_id, after, duration_minutes, timezone
// tenant_id comes from x-tenant-id header (injected by the API Gateway from JWT).
// Algorithm:
//   1. Load working hours (ae_get_working_hours)
//   2. Search forward day by day (max horizon: 60 days)
//   3. For each day: load busy periods + exceptions, scan working windows for the
//      first gap that fits duration_minutes
//   4. Return { success: true, data: { start, end } } or data: null when none found

const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;

function supabaseRpc(fnName, params) {
  return $helpers.httpRequest({
    method: 'POST',
    url: `${SUPABASE_URL}/rest/v1/rpc/${fnName}`,
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=representation',
    },
    body: JSON.stringify(params),
  });
}

// ── Helpers ───────────────────────────────────────────────────────────────────

function localTimeToMs(dateStr, timeStr, tz) {
  const isoLike = `${dateStr}T${timeStr}:00`;
  const naiveMs = new Date(isoLike + 'Z').getTime();
  const fmt = new Intl.DateTimeFormat('en-US', {
    timeZone: tz,
    year: 'numeric', month: '2-digit', day: '2-digit',
    hour: '2-digit', minute: '2-digit', second: '2-digit',
    hour12: false,
  });
  const parts = fmt.formatToParts(new Date(naiveMs));
  const p = {};
  for (const { type, value } of parts) p[type] = value;
  const localMs = Date.UTC(
    parseInt(p.year), parseInt(p.month) - 1, parseInt(p.day),
    parseInt(p.hour === '24' ? '0' : p.hour), parseInt(p.minute), parseInt(p.second)
  );
  return naiveMs - (localMs - naiveMs);
}

function getDow(tsMs, tz) {
  const parts = new Intl.DateTimeFormat('en-US', {
    timeZone: tz, weekday: 'short',
  }).formatToParts(new Date(tsMs));
  const day = parts.find(p => p.type === 'weekday').value;
  return ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'].indexOf(day);
}

function toDateStr(tsMs, tz) {
  return new Intl.DateTimeFormat('en-CA', {
    timeZone: tz, year: 'numeric', month: '2-digit', day: '2-digit',
  }).format(new Date(tsMs));
}

function overlapsAny(slotStartMs, slotEndMs, busyWindows) {
  for (const b of busyWindows) {
    if (slotStartMs < b.endMs && slotEndMs > b.startMs) return true;
  }
  return false;
}

// ── Main ──────────────────────────────────────────────────────────────────────

const item       = $input.first();
const headers    = item.json.headers || {};
const body       = item.json.body   || {};
const tenantId   = headers['x-tenant-id'];

const { customer_id, after, timezone = 'Europe/Berlin' } = body;
const durationMin  = Number(body.duration_minutes) || 30;
const durationMs   = durationMin * 60 * 1000;
const afterMs      = new Date(after).getTime();
const MAX_DAYS     = 60;
const horizonMs    = afterMs + MAX_DAYS * 86400000;

// Load working hours once (they don't change per day)
let workingHours;
try {
  workingHours = await supabaseRpc('ae_get_working_hours', {
    p_tenant_id: tenantId, p_customer_id: customer_id,
  });
} catch (err) {
  return [{ json: { success: false, error: { code: 'DB_ERROR', message: err.message } } }];
}

const whByDow = {};
for (const wh of (workingHours || [])) {
  const d = wh.day_of_week;
  if (!whByDow[d]) whByDow[d] = [];
  whByDow[d].push(wh);
}

const DAY_MS = 86400000;
let cursor = afterMs;

while (cursor < horizonMs) {
  const dateStr = toDateStr(cursor, timezone);
  const dow     = getDow(cursor, timezone);

  if (whByDow[dow]) {
    // Load busy + exceptions for this specific day
    const dayStartMs = localTimeToMs(dateStr, '00:00', timezone);
    const dayEndMs   = dayStartMs + DAY_MS;

    let busyPeriods, exceptions;
    try {
      [busyPeriods, exceptions] = await Promise.all([
        supabaseRpc('ae_get_busy_periods', {
          p_tenant_id: tenantId, p_customer_id: customer_id,
          p_from: new Date(dayStartMs).toISOString(),
          p_to:   new Date(dayEndMs).toISOString(),
        }),
        supabaseRpc('ae_get_day_exceptions', {
          p_tenant_id:   tenantId, p_customer_id: customer_id,
          p_from_date:   dateStr,
          p_to_date:     dateStr,
        }),
      ]);
    } catch (err) {
      return [{ json: { success: false, error: { code: 'DB_ERROR', message: err.message } } }];
    }

    const dayExceptions = exceptions || [];
    const isClosed = dayExceptions.some(ex => ex.is_closed);

    if (!isClosed) {
      const partialExceptions = dayExceptions
        .filter(ex => !ex.is_closed && ex.start_time_txt && ex.end_time_txt)
        .map(ex => ({
          startMs: localTimeToMs(dateStr, ex.start_time_txt, timezone),
          endMs:   localTimeToMs(dateStr, ex.end_time_txt,   timezone),
        }));

      for (const wh of whByDow[dow]) {
        const bufBefore = (wh.buffer_before_min || 0) * 60000;
        const bufAfter  = (wh.buffer_after_min  || 0) * 60000;

        const winStart = Math.max(localTimeToMs(dateStr, wh.start_time_text, timezone), afterMs);
        const winEnd   = localTimeToMs(dateStr, wh.end_time_text, timezone);

        if (winStart >= winEnd) continue;

        const busyWindows = (busyPeriods || []).map(b => ({
          startMs: new Date(b.start_at).getTime() - bufBefore,
          endMs:   new Date(b.end_at).getTime()   + bufAfter,
        })).concat(partialExceptions);

        let t = winStart;
        while (t + durationMs <= winEnd) {
          if (!overlapsAny(t, t + durationMs, busyWindows)) {
            return [{ json: {
              success: true,
              data: {
                start: new Date(t).toISOString(),
                end:   new Date(t + durationMs).toISOString(),
              },
            } }];
          }
          t += durationMs;
        }
      }
    }
  }

  cursor += DAY_MS;
  // Guard against DST making cursor stall on same date
  const nextDateStr = toDateStr(cursor, timezone);
  if (nextDateStr === toDateStr(cursor - DAY_MS, timezone)) cursor += DAY_MS;
}

// No free slot found within horizon
return [{ json: { success: true, data: null } }];
